const home = $('Fetch Home').first().json;
const feedRaw = $('Fetch Feed').first().json;
const newsRaw = $('Fetch News').first().json;

const you = home.you ?? {};
const cd = home.cooldowns ?? {};
const notifs = home.notifications ?? [];
const eco = home.economy ?? {};
const posts = Array.isArray(feedRaw.posts) ? feedRaw.posts : [];
const news = Array.isArray(newsRaw.news) ? newsRaw.news : [];

let feed = posts.map(p => {
  const cmts = (p.comments||[]).map(c=>`  > ${c.author}: ${(c.content||'').slice(0,80)}`).join('\n');
  return `POST_ID: ${p.id}\nBy: ${p.author} (${p.author_role}) in ${p.community} [+${p.upvotes??0}/-${p.downvotes??0}] ${p.comment_count??0} comments${p.is_own?' [YOURS]':''}\nTitle: ${p.title||''}\n${(p.content||'').slice(0,200)}${cmts?'\n'+cmts:''}`;
}).join('\n---\n');
if(!feed) feed='(Empty feed)';

let newsStr = news.map(n=>`- ${(n.content||'').slice(0,200)}`).join('\n') || '(No news)';
let notifStr = notifs.map(n=>`- ${n.type} from ${n.from_agent||'?'}`).join('\n') || '(None)';

let cdStr = 'You can post, comment, and vote.';
if(cd.can_post===false && cd.can_comment===false) cdStr='CANNOT post or comment. Vote only.';
else if(cd.can_post===false) cdStr=`CANNOT post (${cd.post_ready_in_minutes}min). Can comment and vote.`;
else if(cd.can_comment===false) cdStr='Can post but CANNOT comment.';

const context = `YOUR STATUS:\nEnergy: ${you.energy??0} | ${cdStr}\nCommunity: ${eco.total_active_agents??'?'} minds, ${eco.posts_last_24h??'?'} posts today\n\nNOTIFICATIONS:\n${notifStr}\n\nFEED:\n${feed}\n\nNEWS:\n${newsStr}`;

return [{json:{context}}];

let input = $input.first().json;
let postId = '', content = '';
try {
  const parsed = JSON.parse(input.query || '{}');
  postId = parsed.post_id || '';
  content = parsed.content || '';
} catch(e) {
  postId = input.query || '';
}
return JSON.stringify({action: 'comment', post_id: postId.trim(), content: content, status: 'queued'});

let input = $input.first().json;
let title = '', content = '', community = 'general';
try {
  const parsed = JSON.parse(input.query || '{}');
  title = parsed.title || '';
  content = parsed.content || '';
  community = parsed.community || 'general';
} catch(e) {}
return JSON.stringify({action: 'post', title: title, content: content, community: community, status: 'queued'});

let input = $input.first().json;
let memContent = '', memType = 'insight';
try {
  const parsed = JSON.parse(input.query || '{}');
  memContent = parsed.content || '';
  memType = parsed.type || 'insight';
} catch(e) {
  memContent = input.query || '';
}
return JSON.stringify({action: 'memory', content: memContent, type: memType, status: 'queued'});

// The agent outputs its final text in $input.first().json.output
// We look for the ACTIONS_JSON_START/END markers
const raw = $input.first().json;

// Try multiple possible output locations
const text = raw.output || raw.text || raw.response || (typeof raw === 'string' ? raw : JSON.stringify(raw));

const actions = [];

// Method 1: Look for ACTIONS_JSON_START markers
const markerMatch = text.match(/ACTIONS_JSON_START\s*\n?([\s\S]*?)\n?\s*ACTIONS_JSON_END/);
if (markerMatch) {
  try {
    const parsed = JSON.parse(markerMatch[1].trim());
    if (Array.isArray(parsed)) {
      for (const a of parsed) {
        if (a.action) actions.push({...a, _type: a.action});
      }
    }
  } catch(e) {}
}

// Method 2: Look for any JSON array in the text
if (actions.length === 0) {
  const arrayMatch = text.match(/\[\s*\{[\s\S]*?\}\s*\]/);
  if (arrayMatch) {
    try {
      const parsed = JSON.parse(arrayMatch[0]);
      if (Array.isArray(parsed)) {
        for (const a of parsed) {
          if (a.action) actions.push({...a, _type: a.action});
        }
      }
    } catch(e) {}
  }
}

// Method 3: Look for individual action objects
if (actions.length === 0) {
  const objMatches = [...text.matchAll(/\{"action"\s*:\s*"(upvote|downvote|comment|post|memory)"[^}]*\}/g)];
  for (const m of objMatches) {
    try {
      const a = JSON.parse(m[0]);
      if (a.action) actions.push({...a, _type: a.action});
    } catch(e) {}
  }
}

if (actions.length === 0) {
  return [{json: {_type: 'none', summary: 'No actions parsed from: ' + text.substring(0, 200)}}];
}

return actions.map(a => ({json: a}));
